UPDATE coaching.exercise SET
  name = 'Tall-Kneeling Medicine Ball Chest Pass',
  description = 'Perform Tall-Kneeling Medicine Ball Chest Pass with a medicine ball to train upper-body throw speed with leg drive removed so trunk stiffness is exposed. The load, distance, partner input, and volume should preserve the card''s phase intent.',
  card_summary = 'Tall-Kneeling Medicine Ball Chest Pass is a medicine-ball exercise for upper-body throw speed with leg drive removed so trunk stiffness is exposed. Use it when that quality is the priority, not as random ball work or fatigue entertainment.',
  coach_language = 'Primary subrole: jump_throw_explosive_power. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.',
  athlete_language = 'Move the ball with intent, own your posture, and reset before the next rep.',
  movement_family = 'Kneeling upper-body power',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'tall_kneeling_med_ball_chest_pass_power',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 95,
  movement_requirements = '{"primary_joint_actions":["shoulder flexion/extension and elbow extension","trunk bracing and rib-pelvis control"],"primary_tissues":["pecs","triceps","anterior shoulder","abdominals","deep core","spinal stabilizers"],"breathing_demand":"brace_then_exhale","balance_demand":"low","coordination_demand":"high","impact_level":1,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"output_profile":{"freshness_required":true,"quality_rule":"every rep must be fast, accurate, and controlled; stop when ball speed or posture drops"}}'::jsonb,
  coaching_execution = '{"movement_description":"Tall-Kneeling Medicine Ball Chest Pass uses the medicine ball to train upper-body throw speed with leg drive removed so trunk stiffness is exposed. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Use a solid wall target and stand far enough away that the ball returns safely, if it returns at all.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Load hips, trunk, and hands into the starting shape.","Throw the ball with maximal intent while keeping the torso organized.","Catch, recover, or collect the ball safely.","Reset posture before the next attempt."],"coach_cues":["Fast ball.","Brace then throw.","Throw through the target.","Reset between reps."],"common_faults":["Choosing a ball too heavy for speed.","Leaking through the ribs or low back.","Over-rotating after release.","Counting slow, inaccurate throws as good reps."],"breathing_cues":["Breathe in during load.","Exhale sharply on release.","Use calm breaths between attempts."],"quality_gate":["Ball speed, catch quality, or load path stays consistent across the set.","Ribs, pelvis, and spine stay organized without pain.","Athlete can reset safely before the next rep or interval."],"stop_signs":["Pain, dizziness, breath-holding panic, or unsafe ball rebound.","Throw, slam, catch, or footwork quality drops for two consecutive reps.","Partner spacing, wall target, or floor conditions become unsafe."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["heavy strength","sprint or throwing skill","late conditioning"],"pairs_well_after":["general warm-up","dynamic mobility","light trunk activation"],"good_for_sessions":[],"avoid_before":[],"avoid_after":[],"do_not_use_when":["athlete is already fatigued","shoulder/back pain is present","space or rebound is unsafe"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo: Tall-Kneeling Medicine Ball Chest Pass front and side views","Internal coaching reference: medicine-ball and slam-ball load/rebound safety checklist"],"internal_notes":["Film from front and side. Approve progression only when ball speed, posture, catch quality, and spacing stay repeatable."]}'::jsonb,
  participant_structure = 'individual',
