UPDATE coaching.exercise SET
  name = 'Slam Ball Rainbow Slam',
  description = 'Perform Slam Ball Rainbow Slam with a slam ball to train large arc control, lateral trunk timing, and explosive finish without losing posture. The load, distance, partner input, and volume should preserve the card''s phase intent.',
  card_summary = 'Slam Ball Rainbow Slam is a slam-ball exercise for large arc control, lateral trunk timing, and explosive finish without losing posture. Use it when that quality is the priority, not as random ball work or fatigue entertainment.',
  coach_language = 'Primary subrole: jump_throw_explosive_power. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.',
  athlete_language = 'Move the ball with intent, own your posture, and reset before the next rep.',
  movement_family = 'Arc-to-slam power',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'slam_ball_rainbow_slam_power',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = NULL,
  default_rest_seconds = 75,
  est_seconds_per_set = 95,
  movement_requirements = '{"primary_joint_actions":["thoracic rotation and hip pivot","trunk bracing and rib-pelvis control","hip hinge and hip extension"],"primary_tissues":["obliques","hips","thoracic spine","abdominals","deep core","spinal stabilizers","glutes","hamstrings"],"breathing_demand":"brace_then_exhale","balance_demand":"moderate","coordination_demand":"high","impact_level":2,"implement_profile":{"ball_type":"slam_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"output_profile":{"freshness_required":true,"quality_rule":"every rep must be fast, accurate, and controlled; stop when ball speed or posture drops"}}'::jsonb,
  coaching_execution = '{"movement_description":"Slam Ball Rainbow Slam uses the slam ball to train large arc control, lateral trunk timing, and explosive finish without losing posture. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a slam ball that matches the drill intent and athlete size.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Set the feet, ribs, and hips before lifting the ball.","Drive the ball hard into the floor without losing trunk position.","Recover the ball with a hinge or squat pattern instead of rounding the back.","Reset fully before the next rep unless this card is explicitly being used as late-session conditioning."],"coach_cues":["Ribs down.","Slam through the floor.","Hinge to recover.","Fast rep, quiet reset."],"common_faults":["Using a ball that is too heavy to move fast.","Arching overhead or rounding during pickup.","Turning quality reps into a fatigue race.","Letting the ball bounce unpredictably into the face or partner space."],"breathing_cues":["Inhale during setup.","Sharp exhale on the slam.","Breathe normally during the reset."],"quality_gate":["Ball speed, catch quality, or load path stays consistent across the set.","Ribs, pelvis, and spine stay organized without pain.","Athlete can reset safely before the next rep or interval."],"stop_signs":["Pain, dizziness, breath-holding panic, or unsafe ball rebound.","Throw, slam, catch, or footwork quality drops for two consecutive reps.","Partner spacing, wall target, or floor conditions become unsafe."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["heavy strength","sprint or throwing skill","late conditioning"],"pairs_well_after":["general warm-up","dynamic mobility","light trunk activation"],"good_for_sessions":[],"avoid_before":[],"avoid_after":[],"do_not_use_when":["athlete is already fatigued","shoulder/back pain is present","space or rebound is unsafe"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo: Slam Ball Rainbow Slam front and side views","Internal coaching reference: medicine-ball and slam-ball load/rebound safety checklist"],"internal_notes":["Film from front and side. Approve progression only when ball speed, posture, catch quality, and spacing stay repeatable."]}'::jsonb,
  participant_structure = 'individual',
