-- Medicine Ball Russian Twist - Controlled (medicine-ball-russian-twist-controlled)
UPDATE coaching.exercise SET
  name = 'Medicine Ball Russian Twist - Controlled',
  description = 'Perform Medicine Ball Russian Twist - Controlled with a medicine ball to train controlled rotation through the trunk without lumbar whipping or momentum. The load, distance, partner input, and volume should preserve the card''s phase intent.',
  card_summary = 'Medicine Ball Russian Twist - Controlled is a medicine-ball exercise for controlled rotation through the trunk without lumbar whipping or momentum. Use it when that quality is the priority, not as random ball work or fatigue entertainment.',
  coach_language = 'Primary subrole: trunk_pelvis_anti_movement_control. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.',
  athlete_language = 'Move the ball with intent, own your posture, and reset before the next rep.',
  movement_family = 'Controlled rotation strength',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
  primary_order_slot = 'controlled_med_ball_russian_twist',
  default_sets = 2,
  default_reps = 8,
  default_work_seconds = 30,
  default_rest_seconds = 45,
  est_seconds_per_set = 75,
  movement_requirements = '{"primary_joint_actions":["thoracic rotation and hip pivot","trunk bracing and rib-pelvis control"],"primary_tissues":["obliques","hips","thoracic spine","abdominals","deep core","spinal stabilizers"],"breathing_demand":"steady_controlled","balance_demand":"moderate","coordination_demand":"moderate","impact_level":0,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."}}'::jsonb,
  coaching_execution = '{"movement_description":"Medicine Ball Russian Twist - Controlled uses the medicine ball to train controlled rotation through the trunk without lumbar whipping or momentum. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Set ribs, pelvis, and ball position before moving.","Move the ball or body slowly enough to keep the trunk quiet.","Exhale through the hardest part of the rep.","End the set when the athlete loses alignment or breath control."],"coach_cues":["Brace and breathe.","Move the ball, not the spine.","Slow is strong.","Own the finish."],"common_faults":["Using momentum instead of trunk control.","Holding breath or flaring the ribs.","Moving into pain or low-back extension.","Choosing a ball too heavy for the position."],"breathing_cues":["Slow nasal inhale before the rep.","Long exhale through the effort.","Do not hold the breath to survive the set."],"quality_gate":["Ball speed, catch quality, or load path stays consistent across the set.","Ribs, pelvis, and spine stay organized without pain.","Athlete can reset safely before the next rep or interval."],"stop_signs":["Pain, dizziness, breath-holding panic, or unsafe ball rebound.","Throw, slam, catch, or footwork quality drops for two consecutive reps.","Partner spacing, wall target, or floor conditions become unsafe."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["capacity accessories","cooldown","controlled conditioning"],"pairs_well_after":["activation","light throws","main Output work"],"good_for_sessions":[],"avoid_before":[],"avoid_after":[],"do_not_use_when":["pain or guarding","breath control fails","loaded catch is too aggressive"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo: Medicine Ball Russian Twist - Controlled front and side views","Internal coaching reference: medicine-ball and slam-ball load/rebound safety checklist"],"internal_notes":["Film from front and side. Approve progression only when ball speed, posture, catch quality, and spacing stay repeatable."]}'::jsonb,
  participant_structure = 'individual',
  updated_at = now()
WHERE slug = 'medicine-ball-russian-twist-controlled';

