UPDATE coaching.exercise SET
  name = 'Medicine Ball Catch-to-Decel Stick',
  description = 'Perform Medicine Ball Catch-to-Decel Stick with a medicine ball to train incoming load absorption, deceleration mechanics, and controlled athletic stop. The load, distance, partner input, and volume should preserve the card''s phase intent.',
  card_summary = 'Medicine Ball Catch-to-Decel Stick is a medicine-ball exercise for incoming load absorption, deceleration mechanics, and controlled athletic stop. Use it when that quality is the priority, not as random ball work or fatigue entertainment.',
  coach_language = 'Primary subrole: landing_braking_control. Coach the ball as a constraint: choose the load and setup that make the athlete move better, faster, or with more control; stop before fatigue changes the pattern.',
  athlete_language = 'Move the ball with intent, own your posture, and reset before the next rep.',
  movement_family = 'Catch and braking control',
  primary_phase_key = 'resilience',
  phase_subrole = 'landing_braking_control',
  primary_order_slot = 'med_ball_catch_to_decel_stick',
  default_sets = 2,
  default_reps = 8,
  default_work_seconds = 30,
  default_rest_seconds = 45,
  est_seconds_per_set = 75,
  movement_requirements = '{"primary_joint_actions":["acceleration/deceleration footwork","braking and force absorption","trunk bracing and rib-pelvis control"],"primary_tissues":["calves","feet","hips","ankles","quadriceps","abdominals","deep core","spinal stabilizers"],"breathing_demand":"steady_controlled","balance_demand":"moderate","coordination_demand":"high","impact_level":2,"implement_profile":{"ball_type":"medicine_ball","load_rule":"Light enough for speed and accuracy on Output cards; heavy enough for control only on Capacity cards; never choose load that changes the pattern.","surface_rule":"Use wall/floor/partner setup that matches ball rebound behavior. Dead slam balls should not be expected to rebound."},"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"safe toss, catch, target, cue, or ball exchange defined by the card","quality_rule":"stop before timing, catch quality, spacing, communication, or decision quality degrades"}}'::jsonb,
  coaching_execution = '{"movement_description":"Medicine Ball Catch-to-Decel Stick uses the medicine ball to train incoming load absorption, deceleration mechanics, and controlled athletic stop. The drill is valuable only when the athlete can keep the intended phase quality, safe spacing, and repeatable mechanics.","setup":["Choose a medicine ball that matches the drill intent and athlete size.","Pair athletes by size, skill, maturity, and ability to follow stop commands.","Clear the lane, wall, floor, or partner space before the first rep.","Explain the finish position and stop command before adding speed."],"execution_steps":["Start in the agreed base position with eyes on the cue or ball.","Receive, throw, or move only after the cue is clear.","Stick or finish the rep with foot pressure, trunk position, and safe spacing.","Reset before adding speed, distance, or unpredictability."],"coach_cues":["See it first.","Catch with posture.","Brake before you rush.","Reset clean."],"common_faults":["Guessing before the cue.","Catching with soft trunk or late hands.","Drifting into another athlete''s space.","Adding chaos before the base pattern is clean."],"breathing_cues":["Stay relaxed before the cue.","Exhale on catch, throw, or stick.","Recover breathing during the reset."],"quality_gate":["Ball speed, catch quality, or load path stays consistent across the set.","Ribs, pelvis, and spine stay organized without pain.","Athlete can reset safely before the next rep or interval."],"stop_signs":["Pain, dizziness, breath-holding panic, or unsafe ball rebound.","Throw, slam, catch, or footwork quality drops for two consecutive reps.","Partner spacing, wall target, or floor conditions become unsafe."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["capacity accessories","cooldown","controlled conditioning"],"pairs_well_after":["activation","light throws","main Output work"],"good_for_sessions":[],"avoid_before":[],"avoid_after":[],"do_not_use_when":["pain or guarding","breath control fails","loaded catch is too aggressive"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal demo: Medicine Ball Catch-to-Decel Stick front and side views","Internal coaching reference: medicine-ball and slam-ball load/rebound safety checklist"],"internal_notes":["Film from front and side. Approve progression only when ball speed, posture, catch quality, and spacing stay repeatable."]}'::jsonb,
