  counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning
)
SELECT e.id,
  FALSE, 2, 24,
  TRUE, FALSE, FALSE,
  TRUE, TRUE
FROM coaching.exercise e
WHERE e.slug = 'slam-ball-sprawl-to-slam'
  AND NOT EXISTS (SELECT 1 FROM coaching.exercise_regimen_rule rr WHERE rr.exercise_id = e.id);

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 4,
  impact_level = 3,
  requires_spotting = FALSE,
  requires_coach_supervision = 'required',
  readiness_checks = ARRAY['Athlete can brace and breathe without pain.', 'Ball weight and rebound behavior are appropriate for the drill.', 'Space, wall, floor, and partner lane are clear before starting.']::text[],
  contraindications = ARRAY['Current back, shoulder, wrist, hip, knee, or abdominal pain aggravated by the pattern.', 'Inability to control the ball path or stop command.', 'Unsafe wall, floor, rebound, or partner spacing.']::text[],
  common_substitutions = ARRAY[]::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'slam-ball-sprawl-to-slam';

INSERT INTO coaching.exercise_safety_profile (
  exercise_id, risk_level, impact_level, requires_spotting, requires_coach_supervision,
  readiness_checks, contraindications, common_substitutions
)
SELECT e.id, 4, 3, FALSE,
  'required',
  ARRAY['Athlete can brace and breathe without pain.', 'Ball weight and rebound behavior are appropriate for the drill.', 'Space, wall, floor, and partner lane are clear before starting.']::text[], ARRAY['Current back, shoulder, wrist, hip, knee, or abdominal pain aggravated by the pattern.', 'Inability to control the ball path or stop command.', 'Unsafe wall, floor, rebound, or partner spacing.']::text[], ARRAY[]::text[]
FROM coaching.exercise e
WHERE e.slug = 'slam-ball-sprawl-to-slam'
  AND NOT EXISTS (SELECT 1 FROM coaching.exercise_safety_profile sp WHERE sp.exercise_id = e.id);

