-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for medicine-ball and slam-ball work: explosive throws, trunk control, catch/decel skill, and loaded ball strength with phase-honest placement.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('medicine-ball-chest-pass', 'The ball gives immediate feedback: speed, accuracy, rebound, catch quality, or load path changes when the athlete leaks force. Medicine Ball Chest Pass therefore links bracing, timing, and force transfer in a coachable way.', 'Belongs in Output because the drill expresses high-quality speed, power, throwing intent, stiffness, or reactive athleticism while fresh. The slot `jump_throw_explosive_power` keeps it away from fatigue-based conditioning.', 'Use after Prepare & Access and any needed Movement Intelligence, before heavy strength, conditioning, or high-volume sport work. Keep volume low, intent high, and rest long enough for every throw, slam, or rebound to look sharp.', 'The common mistake is turning a power drill into conditioning by using too many reps, too heavy a ball, short rest, or counting slow throws after speed and posture have dropped.', 'Scale by reducing ball load, distance, rotation range, approach speed, or reactive demand before increasing volume. Progress only one variable at a time and let the quality gate decide.'),
